+#[derive(Debug, Clone, PartialEq, Eq)]
+pub enum LocItem {
+    /// Field name (string).
+    Field(String),
+    /// Array index (integer).
+    Index(usize),
+}
+
+impl LocItem {
+    /// Create a field location item.
+    #[must_use]
