+
+fn preview_body(body: &Body, max_bytes: usize) -> Option<String> {
+    if max_bytes == 0 {
+        return None;
+    }
+    match body {
+        Body::Empty => None,
+        Body::Bytes(bytes) => {
+            if bytes.is_empty() {
