+
+fn preview_response_body(body: &crate::response::ResponseBody, max_bytes: usize) -> Option<String> {
+    if max_bytes == 0 {
+        return None;
+    }
+    match body {
+        crate::response::ResponseBody::Empty => None,
+        crate::response::ResponseBody::Bytes(bytes) => {
+            if bytes.is_empty() {
