+    /// Create a streaming response from a file with custom config.
+    ///
+    /// # Errors
+    ///
+    /// Returns an error if the file cannot be opened.
+    fn stream_file_with_config<P: AsRef<Path>>(
+        path: P,
+        cx: Cx,
+        content_type: &[u8],
+        config: StreamConfig,
+    ) -> io::Result<fastapi_core::Response>;
