+impl StreamingResponseExt for fastapi_core::Response {
+    fn stream_file<P: AsRef<Path>>(
+        path: P,
+        cx: Cx,
+        content_type: &[u8],
+    ) -> io::Result<fastapi_core::Response> {
+        Self::stream_file_with_config(path, cx, content_type, StreamConfig::default())
