+    }
+
+    /// Format as an HTTP Allow header value.
+    #[must_use]
+    pub fn header_value(&self) -> String {
+        let mut out = String::new();
+        for (idx, method) in self.methods.iter().enumerate() {
+            if idx > 0 {
+                out.push_str(", ");
+            }
+            out.push_str(method.as_str());
+        }
+        out
+    }
