+fn method_order(method: &Method) -> u8 {
+    match *method {
+        Method::Get => 0,
+        Method::Head => 1,
+        Method::Post => 2,
+        Method::Put => 3,
+        Method::Delete => 4,
+        Method::Patch => 5,
+        Method::Options => 6,
+        Method::Trace => 7,
+    }
